        <marker id="nif-amber" markerWidth="11" markerHeight="11" refX="9" refY="5.5" orient="auto"><path d="M 0 0 L 11 5.5 L 0 11" fill="none" stroke="#D97706" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round"/></marker>
